using Microsoft.VisualStudio.TestTools.UnitTesting;
using Contoso.Text;

namespace Contoso.Text.Tests;

[TestClass]
public class StringFormatterTests
{
    private readonly StringFormatter _formatter = new();

    // --- FormatPhoneNumber tests ---

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_StartsWithAreaCodeInParens()
    {
        string result = _formatter.FormatPhoneNumber("2125551234");

        StringAssert.StartsWith(result, "(212)");
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_EndsWithLastFourDigits()
    {
        string result = _formatter.FormatPhoneNumber("2125551234");

        StringAssert.EndsWith(result, "1234");
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ContainsHyphen()
    {
        string result = _formatter.FormatPhoneNumber("2125551234");

        StringAssert.Contains(result, "-");
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ReturnsExpectedFormat()
    {
        string result = _formatter.FormatPhoneNumber("2125551234");

        Assert.AreEqual("(212) 555-1234", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_NullInput_ThrowsArgumentNullException()
    {
        Assert.ThrowsException<ArgumentNullException>(
            () => _formatter.FormatPhoneNumber(null!));
    }

    [TestMethod]
    public void FormatPhoneNumber_TooFewDigits_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _formatter.FormatPhoneNumber("12345"));
    }

    [TestMethod]
    public void FormatPhoneNumber_TooManyDigits_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _formatter.FormatPhoneNumber("12345678901"));
    }

    // --- BuildGreeting tests ---

    [TestMethod]
    public void BuildGreeting_DefaultTitle_StartsWithDearMr()
    {
        string result = _formatter.BuildGreeting("Smith");

        StringAssert.StartsWith(result, "Dear Mr.");
    }

    [TestMethod]
    public void BuildGreeting_DefaultTitle_EndsWithComma()
    {
        string result = _formatter.BuildGreeting("Smith");

        StringAssert.EndsWith(result, ",");
    }

    [TestMethod]
    public void BuildGreeting_DefaultTitle_ContainsName()
    {
        string result = _formatter.BuildGreeting("Smith");

        StringAssert.Contains(result, "Smith");
    }

    [TestMethod]
    public void BuildGreeting_CustomTitle_StartsWithDearAndTitle()
    {
        string result = _formatter.BuildGreeting("Johnson", "Dr.");

        StringAssert.StartsWith(result, "Dear Dr.");
    }

    [TestMethod]
    public void BuildGreeting_CustomTitle_ReturnsExpectedFormat()
    {
        string result = _formatter.BuildGreeting("Johnson", "Dr.");

        Assert.AreEqual("Dear Dr. Johnson,", result);
    }

    [TestMethod]
    public void BuildGreeting_NullName_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _formatter.BuildGreeting(null!));
    }

    [TestMethod]
    public void BuildGreeting_WhitespaceName_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _formatter.BuildGreeting("   "));
    }

    // --- GenerateSlug tests ---

    [TestMethod]
    public void GenerateSlug_SimpleTitle_ReturnsLowercaseWithHyphens()
    {
        string result = _formatter.GenerateSlug("Hello World");

        Assert.AreEqual("hello-world", result);
    }

    [TestMethod]
    public void GenerateSlug_TitleWithSpecialChars_DoesNotStartWithHyphen()
    {
        string result = _formatter.GenerateSlug("  --Hello World--  ");

        // Should not start or end with hyphens after trimming
        Assert.IsFalse(result.StartsWith('-'));
        Assert.IsFalse(result.EndsWith('-'));
    }

    [TestMethod]
    public void GenerateSlug_MultipleSpaces_CollapsesToSingleHyphen()
    {
        string result = _formatter.GenerateSlug("Hello   World");

        StringAssert.Contains(result, "hello-world");
        Assert.IsFalse(result.Contains("--"));
    }

    [TestMethod]
    public void GenerateSlug_MixedCaseAndSymbols_ReturnsCleanSlug()
    {
        string result = _formatter.GenerateSlug("My Blog Post! #1");

        Assert.AreEqual("my-blog-post-1", result);
    }

    [TestMethod]
    public void GenerateSlug_MatchesSlugPattern()
    {
        string result = _formatter.GenerateSlug("C# Is Great @ Programming");

        StringAssert.Matches(result, new System.Text.RegularExpressions.Regex(@"^[a-z0-9]+(-[a-z0-9]+)*$"));
    }

    [TestMethod]
    public void GenerateSlug_NullTitle_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentNullException>(
            () => _formatter.GenerateSlug(null!));
    }

    [TestMethod]
    public void GenerateSlug_WhitespaceTitle_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _formatter.GenerateSlug("   "));
    }

    // --- FormatCurrency tests ---

    [TestMethod]
    public void FormatCurrency_DefaultSymbol_StartsWithDollarSign()
    {
        string result = _formatter.FormatCurrency(9.99m);

        StringAssert.StartsWith(result, "$");
    }

    [TestMethod]
    public void FormatCurrency_CustomSymbol_StartsWithSymbol()
    {
        string result = _formatter.FormatCurrency(19.99m, "€");

        StringAssert.StartsWith(result, "€");
    }

    [TestMethod]
    public void FormatCurrency_WholeNumber_EndsWithTwoDecimalPlaces()
    {
        string result = _formatter.FormatCurrency(100m);

        StringAssert.EndsWith(result, ".00");
    }

    [TestMethod]
    public void FormatCurrency_FractionalAmount_FormatsToTwoDecimals()
    {
        string result = _formatter.FormatCurrency(42.5m);

        Assert.AreEqual("$42.50", result);
    }

    [TestMethod]
    public void FormatCurrency_NegativeAmount_ContainsMinusSign()
    {
        string result = _formatter.FormatCurrency(-15.75m);

        StringAssert.Contains(result, "-");
        Assert.AreEqual("$-15.75", result);
    }

    [TestMethod]
    public void FormatCurrency_Zero_ReturnsSymbolWithZeroes()
    {
        string result = _formatter.FormatCurrency(0m);

        Assert.AreEqual("$0.00", result);
    }
}

